import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "./Navbar.css";

function Navbar({ cartCount, setSearch, setCategory }) {
  const [input, setInput] = useState("");
  const [products, setProducts] = useState([]);
  const [suggestions, setSuggestions] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5001/products")
      .then((res) => res.json())
      .then((data) => setProducts(data));
  }, []);

  const handleChange = (e) => {
    const value = e.target.value;
    setInput(value);
    setSearch(value);

    if (value.length > 0) {
      const lower = value.toLowerCase();

      // 🔥 Product suggestions
      const productMatches = products.filter((item) =>
        item.name.toLowerCase().includes(lower)
      );

      // 🔥 Category suggestions
      const categories = [...new Set(products.map(p => p.category))];

      const categoryMatches = categories.filter((cat) =>
        cat.toLowerCase().includes(lower)
      );

      // Combine both
      const combined = [
        ...categoryMatches.map((cat) => ({ type: "category", value: cat })),
        ...productMatches.map((item) => ({ type: "product", value: item }))
      ];

      setSuggestions(combined.slice(0, 6));
    } else {
      setSuggestions([]);
    }
  };

  return (
    <div className="navbar">
      <h2>Flipkart Clone</h2>

      <div className="search-container">
        <input
          type="text"
          placeholder="Search for products or categories..."
          value={input}
          onChange={handleChange}
        />

        {/* 🔥 Suggestions */}
        {suggestions.length > 0 && (
          <div className="suggestions">

            {suggestions.map((item, index) => {

              // 👉 CATEGORY CLICK
              if (item.type === "category") {
                return (
                  <div
                    key={index}
                    className="suggestion-item"
                    onClick={() => {
                      setCategory(item.value);
                      setSearch("");
                      setInput("");
                      setSuggestions([]);
                    }}
                  >
                    🔎 {item.value} (Category)
                  </div>
                );
              }

              // 👉 PRODUCT CLICK
              return (
                <Link
                  key={index}
                  to={`/product/${item.value.id}`}
                  className="suggestion-item"
                  onClick={() => setSuggestions([])}
                >
                  {item.value.name}
                </Link>
              );
            })}

          </div>
        )}
      </div>

      <Link to="/cart">Cart ({cartCount})</Link>
    </div>
  );
}

export default Navbar;
